const rows = $input.all().map((item) => item.json || {});
const sourceRow = rows.find((row) => row.rawRelease) || rows.find((row) => row.fullEvidence) || rows.find((row) => row.prompt) || rows[0] || {};
const rawRelease = sourceRow.rawRelease || null;
const fullEvidence = sourceRow.fullEvidence || null;
const legacyPrompt = String(sourceRow.prompt || sourceRow.aiPrompt || sourceRow.readmePrompt || '').trim() || null;
const release = rawRelease?.release || fullEvidence?.release || sourceRow.release || {};
const batchCommitSize = Math.max(1, Math.min(Number(sourceRow.batchCommitSize || sourceRow.batchSize || 5), 20));

if (!rawRelease && !fullEvidence && !legacyPrompt) {
  throw new Error('Missing release evidence. Expected rawRelease, fullEvidence or prompt from workflow 04.');
}

return [{
  json: {
    kind: 'technicalBatchPipelineInput',
    release,
    rawRelease,
    fullEvidence,
    legacyPrompt,
    batchCommitSize
  }
}];

const input = $input.first().json || {};
const rawRelease = input.rawRelease || {};
const fullEvidence = input.fullEvidence || {};

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function chunk(items, size) {
  const result = [];
  for (let index = 0; index < items.length; index += size) {
    result.push(items.slice(index, index + size));
  }
  return result;
}

function unique(values) {
  return [...new Set(values.filter(Boolean))];
}

function cleanCommitMessage(message) {
  const text = String(message || '').replace(/\/\*+/g, ' ').replace(/\*+\//g, ' ').replace(/\s+/g, ' ').trim();
  return text || 'Sin detalle de mensaje';
}

function sanitizeCommit(commit) {
  return {
    ...commit,
    message: cleanCommitMessage(commit?.message),
  };
}

function sanitizeIssue(issue) {
  return {
    ...issue,
    comments: asArray(issue?.comments).slice(0, 2),
    worklogs: asArray(issue?.worklogs),
    histories: asArray(issue?.histories),
  };
}

const globalSummary = fullEvidence.diagnostics?.stats || rawRelease.diagnostics?.stats || {};
const commitsWithoutSis = fullEvidence.commitsWithoutSis || rawRelease.diagnostics?.commitsWithoutSIS || [];
const sisWithoutRec = fullEvidence.sisWithoutRec || rawRelease.diagnostics?.sisWithoutREC || [];

if (input.legacyPrompt) {
  return [{
    json: {
      kind: 'technicalBatchRequest',
      batchIndex: 1,
      batchCount: 1,
      batchCommitShas: [],
      batchSisKeys: [],
      release: input.release || {},
      prompt: input.legacyPrompt,
      globalSummary,
      commitsWithoutSis,
      sisWithoutRec
    }
  }];
}

const commits = asArray(rawRelease.commits).map(sanitizeCommit);
const workItems = asArray(rawRelease.workItems).map(sanitizeIssue);
const recItems = asArray(rawRelease.recItems).map(sanitizeIssue);
const relationships = rawRelease.relationships || {};

const commitToSis = asArray(relationships.commitToSis);
const sisToRec = asArray(relationships.sisToRec);

if (!commits.length) {
  const releaseVersion = input.release?.currentVersion || 'sin-version';
  return [{
    json: {
      kind: 'technicalBatchRequest',
      batchIndex: 1,
      batchCount: 1,
      batchCommitShas: [],
      batchSisKeys: [],
      release: input.release || {},
      globalSummary,
      commitsWithoutSis,
      sisWithoutRec,
      prompt: `Release ${releaseVersion}. No hay commits en la evidencia. Genera una nota breve en Markdown indicando que no se encontraron commits para documentar.`
    }
  }];
}

const chunks = chunk(commits, input.batchCommitSize || 5);

return chunks.map((batchCommits, index) => {
  const batchCommitShas = batchCommits.map((commit) => commit.sha).filter(Boolean);
  const batchSisKeys = unique([
    ...batchCommits.flatMap((commit) => asArray(commit.originSisKeys)),
    ...commitToSis.filter((relation) => batchCommitShas.includes(relation.commitSha)).map((relation) => relation.sisKey)
  ]);

  const batchWorkItems = workItems.filter((item) => {
    const key = item?.key || null;
    const originCommitShas = asArray(item?.originCommitShas);
    return batchSisKeys.includes(key) || originCommitShas.some((sha) => batchCommitShas.includes(sha));
  });

  const batchRecKeys = unique([
    ...sisToRec.filter((relation) => batchSisKeys.includes(relation.sisKey)).map((relation) => relation.recKey),
    ...batchWorkItems.flatMap((item) => asArray(item?.relationships?.recKeys))
  ]);

  const batchRecItems = recItems.filter((item) => batchRecKeys.includes(item?.key));

  const batchRelationships = {
    commitToSis: commitToSis.filter((relation) => batchCommitShas.includes(relation.commitSha)),
    sisToRec: sisToRec.filter((relation) => batchSisKeys.includes(relation.sisKey)),
    dependencies: asArray(relationships.dependencies).filter((relation) => batchSisKeys.includes(relation.fromSisKey) || batchSisKeys.includes(relation.toSisKey))
  };

  const batchEvidence = {
    release: rawRelease.release || input.release || {},
    commits: batchCommits,
    workItems: batchWorkItems,
    recItems: batchRecItems,
    relationships: batchRelationships,
    diagnostics: {
      stats: {
        commits: batchCommits.length,
        sis: batchSisKeys.length,
        recs: batchRecKeys.length,
        commitsWithFiles: batchCommits.filter((commit) => asArray(commit.files).length > 0).length,
        filesTotal: batchCommits.reduce((total, commit) => total + asArray(commit.files).length, 0)
      }
    }
  };

  const releaseVersion = input.release?.currentVersion || rawRelease.release?.currentVersion || 'sin-version';
  const evidenceText = JSON.stringify(batchEvidence, null, 2);
  const prompt = `Sos un arquitecto tecnico senior de JSAT.

Genera solamente la documentacion tecnica del lote ${index + 1}/${chunks.length} para la release ${releaseVersion}.

No devuelvas JSON.
No uses bloques de codigo.
No escribas introducciones fuera del Markdown.
No inventes datos.
No generes una portada global de release.
No escribas texto editorial, explicaciones de proceso, ni frases como "este documento fue generado...".

OBJETIVO:
Documentar exclusivamente estos commits: ${batchCommitShas.join(', ') || 'sin commits'}.
SIS impactados en este lote: ${batchSisKeys.join(', ') || 'sin SIS detectados'}.

REGLAS CRITICAS:
- El README del lote debe estar organizado por SIS impactado y por commit dentro de cada SIS.
- Si el mismo SIS aparece en otros lotes, documenta solo la evidencia presente en este lote.
- Para cada commit, lista explicitamente los archivos modificados incluidos en la evidencia.
- No reemplaces la lista de archivos por un resumen narrativo.
- No omitas la seccion Archivos modificados si la evidencia trae archivos.
- Si un archivo no tiene patch, escribe exactamente: Patch no incluido en la evidencia.
- No agregues un titulo global tipo Release al lote.
- No muestres contadores vacios como Comentarios Jira: 0 o Worklogs: 0.
- Si no hay comentarios Jira, omiti esa seccion por completo.
- Si no hay worklogs, omiti esa seccion por completo.
- Si no hay historial, omiti esa seccion por completo.
- Solo emiti la seccion Evidencia incompleta cuando falte algo realmente importante para entender el cambio tecnico del lote.
- No pongas como faltante generico Sin comentarios o Sin worklogs si eso no afecta el entendimiento tecnico del cambio.
- Limpia los mensajes de commit: no muestres delimitadores como /*, */, // o envoltorios decorativos si no aportan informacion.

ESTRUCTURA OBLIGATORIA:
## Lote ${index + 1}

### Resumen del lote
- Commits cubiertos
- SIS impactados
- REC impactados
- Cantidad de archivos

### SIS-XXXX - Titulo
#### Jira
#### REC relacionados
#### Commits asociados
Para cada commit:
- SHA corto
- fecha
- autor
- mensaje limpio
- stats

##### Archivos modificados
Para cada archivo:
- ruta
- estado
- additions
- deletions
- changes
- patch relevante si existe

#### Comentarios Jira
Incluila solo si hay comentarios.
Muestra solo los 2 comentarios mas recientes.

#### Worklogs
Incluila solo si hay worklogs.

#### Historial de estados
Incluila solo si hay historial.

#### Impacto tecnico observado
#### Riesgos tecnicos
#### Pruebas recomendadas
#### Evidencia incompleta
Solo si aplica.

### Commits del lote sin SIS
Solo si aplica.

EVIDENCIA DEL LOTE:
${evidenceText}`;

  return {
    json: {
      kind: 'technicalBatchRequest',
      batchIndex: index + 1,
      batchCount: chunks.length,
      batchCommitShas,
      batchSisKeys,
      release: input.release || rawRelease.release || {},
      globalSummary,
      commitsWithoutSis,
      sisWithoutRec,
      prompt
    }
  };
});

const markdown = String(
  $json.output ||
  $json.text ||
  $json.response ||
  ''
).trim();

return {
  json: {
    kind: 'technicalBatchMarkdown',
    batchIndex: Number($json.batchIndex || 0),
    batchCount: Number($json.batchCount || 0),
    batchCommitShas: Array.isArray($json.batchCommitShas) ? $json.batchCommitShas : [],
    batchSisKeys: Array.isArray($json.batchSisKeys) ? $json.batchSisKeys : [],
    release: $json.release || {},
    globalSummary: $json.globalSummary || {},
    commitsWithoutSis: Array.isArray($json.commitsWithoutSis) ? $json.commitsWithoutSis : [],
    sisWithoutRec: Array.isArray($json.sisWithoutRec) ? $json.sisWithoutRec : [],
    technicalMarkdown: markdown || null,
    status: markdown ? 'generated' : 'emptyResponse'
  }
};

const rows = $input.all().map((item) => item.json || {});
const ordered = rows.sort((a, b) => Number(a.batchIndex || 0) - Number(b.batchIndex || 0));

if (!ordered.length) {
  throw new Error('No technical batch markdown was generated.');
}

function cleanInlineArtifacts(text) {
  return String(text || '')
    .replace(/\/\*+/g, ' ')
    .replace(/\*+\//g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function cleanBatchMarkdown(markdown) {
  let text = String(markdown || '').trim();
  text = text.replace(/^#\s+Release\s+.*?\n+/i, '');
  text = text.replace(/^##\s+Alcance tecnico\n+[\s\S]*?(?=^##\s|^###\s|^##\sLote\s|\Z)/im, '');
  text = text.replace(/^##\s+Resumen de trazabilidad\n+[\s\S]*?(?=^##\s|^###\s|^##\sLote\s|\Z)/im, '');
  text = text.replace(/^[-*]\s+Lotes procesados\s*:\s*.*$/gim, '');
  text = text.replace(/^Este documento fue generado.*$/gim, '');
  text = text.replace(/\/\*+/g, '');
  text = text.replace(/\*+\//g, '');
  text = text.replace(/\n{3,}/g, '\n\n');
  return text.trim();
}

const release = ordered[0]?.release || {};
const releaseVersion = release.currentVersion || 'sin-version';
const globalSummary = ordered[0]?.globalSummary || {};
const commitsWithoutSis = ordered[0]?.commitsWithoutSis || [];
const sisWithoutRec = ordered[0]?.sisWithoutRec || [];

const mergedBatches = ordered
  .map((row) => cleanBatchMarkdown(row.technicalMarkdown))
  .filter(Boolean)
  .join('\n\n---\n\n')
  .trim();

const summaryLines = [
  ['Commits totales', globalSummary.commits],
  ['Commits con archivos', globalSummary.commitsWithFiles],
  ['Archivos totales', globalSummary.filesTotal],
  ['SIS primarios', globalSummary.primarySis],
  ['SIS relacionados', globalSummary.relatedSis],
  ['REC', globalSummary.recs],
  ['SIS con comentarios', globalSummary.sisWithComments]
].filter((entry) => entry[1] !== undefined && entry[1] !== null)
 .map((entry) => `- ${entry[0]}: ${entry[1]}`)
 .join('\n');

const commitsWithoutSisLines = commitsWithoutSis.length
  ? commitsWithoutSis.slice(0, 120).map((commit) => {
      const shortSha = commit?.sha ? String(commit.sha).slice(0, 10) : 'sin-sha';
      const message = cleanInlineArtifacts(commit?.message || 'sin mensaje');
      return `- ${shortSha}: ${message || 'Sin detalle de mensaje'}`;
    }).join('\n')
  : '';

const sisWithoutRecLines = sisWithoutRec.length
  ? sisWithoutRec.map((key) => `- ${key}`).join('\n')
  : '';

let finalReadme = `# Release ${releaseVersion}\n`;

if (summaryLines) {
  finalReadme += `\n## Resumen de trazabilidad\n${summaryLines}\n`;
}

if (mergedBatches) {
  finalReadme += `\n## Cambios detallados\n${mergedBatches}\n`;
}

if (commitsWithoutSisLines) {
  finalReadme += `\n## Commits sin SIS\n${commitsWithoutSisLines}\n`;
}

if (sisWithoutRecLines) {
  finalReadme += `\n## SIS sin REC\n${sisWithoutRecLines}\n`;
}

finalReadme = finalReadme
  .replace(/^Este documento fue generado.*$/gim, '')
  .replace(/\/\*+/g, '')
  .replace(/\*+\//g, '')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

return [{
  json: {
    kind: 'technicalReadmeResult',
    status: finalReadme ? 'generated' : 'emptyResponse',
    technicalReadme: finalReadme || null,
    output: finalReadme || null,
    text: finalReadme || null,
    response: finalReadme || null,
    mergedMarkdown: mergedBatches || null,
    batchSummaries: ordered.map((row) => ({
      batchIndex: row.batchIndex,
      batchCommitShas: row.batchCommitShas || [],
      batchSisKeys: row.batchSisKeys || [],
      status: row.status || 'unknown'
    }))
  }
}];
